WITH db AS (SELECT db.oid AS database_oid, db.datname AS database_name, db.datcollate AS database_collation, db.datconnlimit AS max_connection_limit, db.datistemplate AS is_template_database, PG_ENCODING_TO_CHAR(db.encoding) AS character_set_encoding, PG_DATABASE_SIZE(db.datname) AS total_disk_size_bytes, r.rolname AS owner_name, t.spcname AS tablespace_name, db.datallowconn AS allow_connections, db.datfrozenxid AS frozen_xid, db.datminmxid AS min_mxid FROM pg_database AS db LEFT JOIN pg_roles AS r ON (db.datdba = r.oid) LEFT JOIN pg_tablespace AS t ON (db.dattablespace = t.oid)), db_size AS (SELECT s.datid AS database_oid, s.datname AS database_name, s.numbackends AS backends_connected, s.xact_commit AS txn_commit_count, s.xact_rollback AS txn_rollback_count, s.blks_read AS blocks_read_count, s.blks_hit AS blocks_hit_count, s.tup_returned AS tup_returned_count, s.tup_fetched AS tup_fetched_count, s.tup_inserted AS tup_inserted_count, s.tup_updated AS tup_updated_count, s.tup_deleted AS tup_deleted_count, s.conflicts AS query_conflict_count, s.temp_files AS temporary_file_count, s.temp_bytes AS temporary_file_bytes_written, s.deadlocks AS detected_deadlocks_count, s.checksum_failures AS checksum_failure_count, s.checksum_last_failure AS last_checksum_failure, s.blk_read_time AS block_read_time_ms, s.blk_write_time AS block_write_time_ms, s.session_time AS session_time_ms, s.active_time AS active_time_ms, s.idle_in_transaction_time AS idle_in_transaction_time_ms, s.sessions AS sessions_count, s.sessions_fatal AS fatal_sessions_count, s.sessions_killed AS killed_sessions_count, s.stats_reset AS statistics_last_reset_on FROM pg_stat_database AS s), src AS (SELECT db.database_oid, db.database_name, db.database_collation, db.max_connection_limit, db.is_template_database, db.character_set_encoding, db.total_disk_size_bytes, db.owner_name, db.tablespace_name, db.allow_connections, db.frozen_xid, db.min_mxid, db_size.backends_connected, db_size.txn_commit_count, db_size.txn_rollback_count, db_size.blocks_read_count, db_size.blocks_hit_count, db_size.tup_returned_count, db_size.tup_fetched_count, db_size.tup_inserted_count, db_size.tup_updated_count, db_size.tup_deleted_count, db_size.query_conflict_count, db_size.temporary_file_count, db_size.temporary_file_bytes_written, db_size.detected_deadlocks_count, db_size.checksum_failure_count, db_size.last_checksum_failure, db_size.block_read_time_ms, db_size.block_write_time_ms, db_size.session_time_ms, db_size.active_time_ms, db_size.idle_in_transaction_time_ms, db_size.sessions_count, db_size.fatal_sessions_count, db_size.killed_sessions_count, db_size.statistics_last_reset_on FROM db LEFT JOIN db_size ON (db.database_oid = db_size.database_oid)) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.database_oid, src.database_name, CHR(34) || VERSION() || CHR(34) AS database_version, CHR(34) || CURRENT_SETTING('server_version_num') || CHR(34) AS database_version_number, src.max_connection_limit, src.is_template_database, src.character_set_encoding, src.total_disk_size_bytes, src.backends_connected, src.txn_commit_count, src.txn_rollback_count, src.blocks_read_count, src.blocks_hit_count, src.tup_returned_count, src.tup_fetched_count, src.tup_inserted_count, src.tup_updated_count, src.tup_deleted_count, src.query_conflict_count, src.temporary_file_count, src.temporary_file_bytes_written, src.detected_deadlocks_count, src.checksum_failure_count, src.last_checksum_failure, src.block_read_time_ms, src.block_write_time_ms, src.session_time_ms, src.active_time_ms, src.idle_in_transaction_time_ms, src.sessions_count, src.fatal_sessions_count, src.killed_sessions_count, COALESCE(TO_CHAR(statistics_last_reset_on, 'YYYY-MM-DD HH24:MI:SS'), '1970-01-01 00:00:00') AS statistics_last_reset_on, INET_SERVER_ADDR() AS inet_server_addr, src.database_collation, src.owner_name, src.tablespace_name, src.allow_connections, src.frozen_xid, src.min_mxid FROM src